sys_script.script:
(function executeRule(current, previous) {

    // Only run when state actually changes to discharge_requested
    if (!current.state.changesTo('discharge_requested')) {
        return;
    }

    function createNotification(userSysId, message) {
        if (!userSysId) {
            return;
        }

        var notif = new GlideRecord('x_1954503_smartc_0_smartcare_notification');
        notif.initialize();
        notif.user = userSysId;
        notif.message = message;
        notif.read = false;
        notif.insert();
    }

    // Doctor notification
    if (current.assigned_doctor) {
        createNotification(
            current.assigned_doctor,
            "Discharge approval needed for patient: " + current.full_name
        );
    }

    // Nurse notification
    if (current.u_assigned_nurse) {
        createNotification(
            current.u_assigned_nurse,
            "Please review discharge for patient: " + current.full_name
        );
    }

    // Patient notification (optional but recommended)
    if (current.patient) { // change this if your patient field name is different
        createNotification(
            current.patient,
            "Your discharge request is being processed."
        );
    }

})(current, previous);
